Defining a generic mathematical vector type supporting float, double, or int structures:

```cpp
template<typename T>
struct TVector3 {
    T X, Y, Z;

    TVector3(T InX, T InY, T InZ) : X(InX), Y(InY), Z(InZ) {}

    TVector3 operator+(const TVector3& Other) const {
        return TVector3(X + Other.X, Y + Other.Y, Z + Other.Z);
    }

    T Dot(const TVector3& Other) const {
        return X * Other.X + Y * Other.Y + Z * Other.Z;
    }
};

void TestTemplate() {
    // Compiler generates two separate struct layouts from the template!
    TVector3<float> FloatVec(1.0f, 2.0f, 3.0f);
    TVector3<int> IntVec(1, 2, 3);
}
```
